    <line x1="60" y1="290" x2="640" y2="290" stroke="rgba(255,255,255,.15)" stroke-width="1"/>
    <rect x="140" y="70" width="180" height="220" rx="6" fill="rgba(248,113,113,.22)" stroke="#f87171" stroke-width="1.5"/>
    <text x="230" y="58" fill="#f87171" font-size="16" font-weight="800" text-anchor="middle" font-family="sans-serif">$6,0 Mrd.</text>
