  <div class="en">
  <svg viewBox="0 0 700 340" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Same Price Move, Different EMV — The Illusion Reported Volume Creates</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Box Ratio math for an identical +5% rally</text>
    <rect x="40" y="70" width="280" height="210" rx="10" fill="rgba(74,222,128,.08)" stroke="#4ade80" stroke-width="1.5"/>
    <text x="180" y="100" fill="#4ade80" font-size="14" font-weight="700" text-anchor="middle" font-family="sans-serif">Real volume only</text>
    <text x="180" y="140" fill="#e4e4e7" font-size="14" text-anchor="middle" font-family="sans-serif">Volume: 500 BTC</text>
    <text x="180" y="164" fill="#e4e4e7" font-size="14" text-anchor="middle" font-family="sans-serif">Box Ratio: small</text>
    <line x1="70" y1="190" x2="290" y2="190" stroke="rgba(255,255,255,.15)" stroke-width="1"/>
